example.code:
import { defineConfig } from 'vitest/config';
export default defineConfig({
  test: {
    environment: 'jsdom',
    globals: true,
    setupFiles: ['./tests/setup.ts'],
    coverage: { provider: 'v8', reporter: ['text', 'html'] },
  },
});

import type { Config } from 'jest';
const config: Config = {
  preset: 'ts-jest',
  testEnvironment: 'jsdom',
  setupFilesAfterFramework: ['./tests/setup.ts'],
  collectCoverageFrom: ['src/**/*.{ts,tsx}'],
};
export default config;

it('formats price with currency symbol', () => {
  // Arrange
  const price = 1234.56;

  // Act
  const result = formatPrice(price, 'USD');

  // Assert
  expect(result).toBe('$1,234.56');
});

it('loads user profile on mount', async () => {
  vi.mocked(fetchUser).mockResolvedValue({ id: 1, name: 'Alice' });

  render(<UserProfile userId={1} />);

  // findBy* waits automatically — no manual waitFor needed
  const name = await screen.findByText('Alice');
  expect(name).toBeInTheDocument();
});

describe('debounced search', () => {
  beforeEach(() => vi.useFakeTimers());
  afterEach(() => vi.useRealTimers());

  it('delays the search call by 300ms', () => {
    const onSearch = vi.fn();
    render(<SearchInput onSearch={onSearch} debounceMs={300} />);

    fireEvent.change(screen.getByRole('textbox'), { target: { value: 'test' } });
    expect(onSearch).not.toHaveBeenCalled();

    vi.advanceTimersByTime(300);
    expect(onSearch).toHaveBeenCalledWith('test');
  });
});

// vitest.config.ts
coverage: {
  provider: 'v8',
  reporter: ['text', 'html', 'lcov'],
  thresholds: {
    lines: 80,
    functions: 80,
    branches: 75,
  },
  exclude: ['**/*.stories.ts', '**/*.d.ts', 'src/index.ts'],
},

// tests/mocks/handlers.ts (MSW v2)
import { http, HttpResponse } from 'msw';

export const handlers = [
  http.get('/api/users/:id', ({ params }) => {
    return HttpResponse.json({ id: params.id, name: 'Alice' });
  }),
  http.post('/api/users', async ({ request }) => {
    const body = await request.json();
    return HttpResponse.json({ id: '123', ...body }, { status: 201 });
  }),
];

// tests/setup.ts
import { setupServer } from 'msw/node';
import { handlers } from './mocks/handlers';

export const server = setupServer(...handlers);

beforeAll(() => server.listen({ onUnhandledRequest: 'error' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

// Good: accessible query
const button = screen.getByRole('button', { name: /submit/i });
const emailInput = screen.getByLabelText('Email address');

// Acceptable: visible text
const heading = screen.getByText('Welcome back');

// Last resort: test ID
const widget = screen.getByTestId('complex-widget');

describe('LoginForm', () => {
  it('calls onSuccess with user data after successful login', async () => {
    const onSuccess = vi.fn();
    render(<LoginForm onSuccess={onSuccess} />);

    await userEvent.type(screen.getByLabelText('Email'), 'user@example.com');
    await userEvent.type(screen.getByLabelText('Password'), 'secret123');
    await userEvent.click(screen.getByRole('button', { name: 'Sign in' }));

    await waitFor(() => {
      expect(onSuccess).toHaveBeenCalledWith(expect.objectContaining({
        email: 'user@example.com',
      }));
    });
  });
});

// tests/setup.ts — mock matchMedia for jsdom
Object.defineProperty(window, 'matchMedia', {
  writable: true,
  value: vi.fn().mockImplementation(query => ({
    matches: false,
    media: query,
    onchange: null,
    addListener: vi.fn(),
    removeListener: vi.fn(),
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    dispatchEvent: vi.fn(),
  })),
});
